#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

#define BUCKET_SIZE 100
#define OUTPUT_RATE 20

int main() {
    int num_packets, i, packet_size, bucket_content = 0;

    printf("Enter the number of packets: ");
    scanf("%d", &num_packets);

    for (i = 1; i <= num_packets; i++) {
        packet_size = rand() % 50 + 10; // Random packet size between 10 and 60
        printf("\nPacket %d arrives with size %d\n", i, packet_size);

        if (packet_size + bucket_content <= BUCKET_SIZE) {
            bucket_content += packet_size;
            printf("Bucket accepts packet. Current content: %d\n", bucket_content);
        } else {
            printf("Bucket overflow! Packet dropped.\n");
        }

        // Simulate output rate
        if (bucket_content >= OUTPUT_RATE) {
            bucket_content -= OUTPUT_RATE;
            printf("Outputting %d bytes. Remaining content: %d\n", OUTPUT_RATE, bucket_content);
        } else if (bucket_content > 0) {
            printf("Outputting %d bytes. Remaining content: 0\n", bucket_content);
            bucket_content = 0;
        }

        sleep(1); // Wait for next tick
    }

    // Empty the remaining bucket
    while (bucket_content > 0) {
        printf("\nNo new packets. Emptying bucket...\n");
        if (bucket_content >= OUTPUT_RATE) {
            bucket_content -= OUTPUT_RATE;
            printf("Outputting %d bytes. Remaining content: %d\n", OUTPUT_RATE, bucket_content);
        } else {
            printf("Outputting %d bytes. Remaining content: 0\n", bucket_content);
            bucket_content = 0;
        }
        sleep(1);
    }

    return 0;
}
